insert into public.locations
  (name, type, category, description, address, city, lat, lng, phone, email, website, tags, lgbt_status, verified)
values
('Family Bar & Club', 'business', 'Nightlife', 'A K Road institution welcoming everyone from drag queens to dancing queens, with nightly entertainment, drag shows and live DJs. A lively, friendly spot to meet new people at the heart of Auckland''s rainbow strip.', '270 Karangahape Road, Auckland CBD', 'Auckland', -36.858, 174.759, '+64 9 309 0213', null, 'https://www.facebook.com/familybarnz', array['drag','dancing','karaoke','nightlife']::text[], null, true),
('The Eagle Bar', 'business', 'Bars', 'A friendly, chilled local gay bar on K Road where you can pick your own tunes on the jukebox and settle in for a good chat. Its relaxed vibe makes it one of the easiest places in Auckland to strike up a conversation.', '259 Karangahape Road, Auckland CBD', 'Auckland', -36.8577, 174.7593, '+64 9 309 4979', 'eaglebar@outlook.co.nz', 'https://www.facebook.com/The.Eagle.Bar/', array['bar','social','jukebox','conversation']::text[], null, true),
('G.A.Y. Auckland', 'business', 'Nightlife', 'One of K Road''s best-loved queer clubs, packed with drag performances, pop anthems and a young, welcoming crowd. In 2025 it expanded with Pink Pony, a connected ground-floor bar, giving you two dance floors to make new friends on.', '262 Karangahape Road, Auckland CBD', 'Auckland', -36.858, 174.7592, '+64 21 028 76649', 'gaybarnz@gmail.com', 'https://www.facebook.com/Gaybarnz/', array['drag','dancing','club','nightlife']::text[], null, true),
('Phoenix Cabaret', 'business', 'Nightlife', 'A glittering K Road cabaret and dinner-show venue created by Kita Mean, winner of RuPaul''s Drag Race Down Under. Shared tables and spectacular drag make it a fun, sociable night out with the community.', 'Level 1, 258 Karangahape Road, Auckland CBD', 'Auckland', -36.858, 174.7593, null, null, 'https://www.phoenixcabaret.co.nz/', array['drag','cabaret','shows','dining']::text[], 'lgbt_owned', true),
('Caluzzi Bar & Cabaret', 'business', 'Nightlife', 'New Zealand''s longest-running drag dinner theatre, serving three-course meals with flair since 1996. The interactive shows and shared celebrations make it a warm, joyful way to experience Auckland''s drag community.', '461 Karangahape Road, Newton, Auckland', 'Auckland', -36.8586, 174.7527, '+64 9 357 0778', null, 'https://www.caluzzi.co.nz/', array['drag','dinner','cabaret','celebration']::text[], null, true),
('Zack''s Bar', 'business', 'Bars', 'A casual gay-owned neighbourhood bar at the top of Parnell Road with drag bingo, quiz nights, speed dating and live comedy through the week. A genuinely welcoming local where regulars and newcomers mix easily.', '421 Parnell Road, Parnell, Auckland 1052', 'Auckland', -36.859, 174.7808, null, null, 'https://www.facebook.com/ZacksBarParnell', array['bar','quiz','drag bingo','neighbourhood']::text[], 'lgbt_owned', true),
('Garnet Station', 'business', 'Cafes', 'A much-loved queer cafe in Westmere serving organic coffee and wood-fired pizza, with the Tiny Theatre out the back hosting shows, quiz nights and community events. A daytime haven for connecting over good food.', '85 Garnet Road, Westmere, Auckland', 'Auckland', -36.8521, 174.7266, null, null, 'http://garnetstation.com/', array['coffee','cafe','theatre','community']::text[], 'lgbt_owned', true),
('The Charlotte Museum Te Whare Takatāpui-Wāhine o Aotearoa', 'resource', 'Community', 'The world''s only museum dedicated to lesbian and sapphic culture and history, doubling as a rainbow community space with regular social events like mix-and-mingles. A unique place to connect with community and heritage.', '1A Howe Street, Freemans Bay, Auckland 1010', 'Auckland', -36.8586, 174.757, null, null, 'https://www.charlottemuseum.co.nz/', array['museum','history','lesbian','events']::text[], 'lgbt_managed', true),
('RainbowYOUTH', 'resource', 'Community', 'Aotearoa''s long-running charity for queer, gender-diverse, takatāpui and intersex young people, with a welcoming drop-in centre just off K Road offering weekly workshops, hangouts and a free community wardrobe. A brilliant first stop for young people looking for friends and support.', '10 Abbey Street, Auckland CBD', 'Auckland', -36.8607, 174.7596, null, null, 'https://ry.org.nz/', array['youth','support','drop-in','peer support']::text[], 'lgbt_managed', true),
('OutLine Aotearoa', 'resource', 'Services', 'A rainbow mental health organisation offering a free, confidential, all-ages support line (0800 OUTLINE, 6pm-9pm nightly) staffed by trained rainbow volunteers, plus counselling and peer support services. A caring ear whenever you need to talk.', 'Level 2, 31 Hargreaves Street, St Marys Bay, Auckland 1011', 'Auckland', -36.848, 174.7407, '0800 688 5463', null, 'https://outline.org.nz/', array['support','counselling','helpline','peer support']::text[], 'lgbt_managed', true),
('Burnett Foundation Aotearoa (Burnett Centre)', 'resource', 'Healthcare', 'Formerly the NZ AIDS Foundation, the Burnett Centre offers free, judgement-free HIV and STI testing with results in 20 minutes, plus counselling and support groups. Friendly staff who understand the community make looking after your health easy.', '35 Hargreaves Street, St Marys Bay, Auckland 1011', 'Auckland', -36.8481, 174.7405, null, null, 'https://www.burnettfoundation.org.nz/', array['sexual health','testing','hiv','support']::text[], 'lgbt_managed', true),
('Body Positive', 'resource', 'Healthcare', 'A peer support organisation founded by and run for people living with HIV, offering testing, advocacy and a genuine sense of community from its Newton base. Connect with people who understand, in a stigma-free space.', '1/3 Poynton Terrace, Newton, Auckland', 'Auckland', -36.8574, 174.7607, '+64 9 309 3989', null, 'https://bodypositive.org.nz/', array['hiv','peer support','testing','community']::text[], 'lgbt_managed', true),
('Auckland Pride', 'resource', 'Community', 'The charitable organisation behind Auckland''s annual Pride Festival, running events, advocacy and community programmes year-round from its K Road office. Volunteering or attending festival events is a fantastic way to meet people across the whole rainbow community.', '281 Karangahape Road, Auckland Central, Auckland 1010', 'Auckland', -36.8578, 174.7588, null, 'kiaora@aucklandpride.org.nz', 'https://aucklandpride.org.nz/', array['festival','events','advocacy','volunteering']::text[], 'lgbt_managed', true),
('Team Auckland Masters Swimmers (TAMS)', 'resource', 'Community', 'A friendly LGBT+ masters swim squad training at the Tepid Baths on Tuesday and Thursday evenings, with regular post-swim social drinks. All abilities are welcome — it''s as much about meeting people as improving your stroke.', 'Tepid Baths, 100 Customs Street West, Auckland CBD', 'Auckland', -36.8437, 174.7625, null, null, 'https://tams.org.nz/', array['swimming','sports','fitness','social']::text[], 'lgbt_managed', true),
('NZ Falcons RFC', 'resource', 'Community', 'New Zealand''s home of gay and inclusive rugby, welcoming players of every experience level to train and play in a supportive environment based at Ponsonby Rugby Club, Western Springs. A great way to find mates, fitness and whānau on and off the field.', 'Western Springs Stadium, Stadium Road, Western Springs, Auckland', 'Auckland', -36.8653, 174.7245, null, null, 'https://nzfalcons.org.nz/', array['rugby','sports','inclusive','teamwork']::text[], 'lgbt_managed', true),
('GALS: Auckland''s Rainbow Choir', 'resource', 'Community', 'New Zealand''s first LGBTQ+ choir, singing together since 1992. This non-auditioned community choir rehearses Tuesday evenings at Pitt Street Methodist Church, and every rehearsal is as much about friendship as it is about music.', 'Pitt Street Methodist Church, 78 Pitt Street, Auckland CBD', 'Auckland', -36.857, 174.7602, null, null, 'https://www.gals.org.nz/', array['choir','music','social','performance']::text[], 'lgbt_managed', true),
('Ivy Bar & Cabaret', 'business', 'Bars', 'Wellington''s much-loved queer bar and cabaret in the basement of the historic James Smith building, hosting drag shows, comedy, quiz and karaoke nights. A deliberately safe, welcoming space where it''s easy to strike up a conversation and find your people.', '63 Cuba Street (basement, James Smith Building), Te Aro', 'Wellington', -41.2892, 174.7767, null, null, 'https://www.ivybar.co.nz/', array['drag','cabaret','karaoke','safe space','nightlife']::text[], 'lgbt_owned', true),
('S&M''s (Scotty & Mal''s) Cocktail & Lounge Bar', 'business', 'Bars', 'A warm, plush cocktail lounge on upper Cuba Street run by Scotty and Mal, known for friendly hosts and a relaxed rainbow crowd. A great spot for unhurried drinks and conversation rather than a big-club night out.', '176 Cuba Street, Te Aro', 'Wellington', -41.2936, 174.7749, null, null, 'https://www.scottyandmals.co.nz/', array['cocktails','lounge','social','nightlife']::text[], 'lgbt_owned', true),
('The Fringe Bar', 'business', 'Nightlife', 'A comedy and cabaret venue just off Courtenay Place with a packed calendar of drag shows, drag king nights and queer-friendly performance events. Shows draw a friendly mixed crowd, making it an easy place to meet people over shared laughs.', '26 Allen Street, Te Aro', 'Wellington', -41.2929, 174.7818, null, null, 'https://thefringebar.co.nz/', array['drag','comedy','cabaret','live shows']::text[], 'ally', true),
('Dirty Little Secret', 'business', 'Nightlife', 'Wellington''s rooftop container bar above Dixon Street, with city views and regular drag bingo and drag events. Its relaxed, sociable atmosphere makes it a popular rainbow-friendly meeting spot in the heart of town.', '7-11 Dixon Street (rooftop), Te Aro', 'Wellington', -41.2915, 174.7785, null, null, 'https://dirtylittlesecret.co.nz/', array['rooftop','drag bingo','drinks','social']::text[], 'ally', true),
('InsideOUT Kōaro', 'resource', 'Community', 'A national rainbow youth charity based in central Wellington, providing support, resources and youth development programmes that help young rainbow and takatāpui people connect with others like them. A brilliant first port of call for anyone under 27 looking for community.', 'Level 3, Anvil House, 138 Wakefield Street, Te Aro', 'Wellington', -41.2886, 174.778, null, null, 'https://insideout.org.nz/', array['youth','support','education','rainbow']::text[], 'lgbt_managed', true),
('Gender Minorities Aotearoa', 'resource', 'Services', 'Aotearoa''s national transgender organisation, run by and for trans, non-binary, irawhiti takatāpui and intersex people from its Newtown hub. Offers peer support, community groups, events, courses and practical help, so there are lots of ways to get involved and meet whānau.', '130 Riddiford Street, Newtown', 'Wellington', -41.3121, 174.7794, '04 385 0611', null, 'https://genderminorities.com/', array['trans','support','peer support','advocacy','housing']::text[], 'lgbt_managed', true),
('Aunty Dana''s Op Shop', 'business', 'Shopping', 'A boutique second-hand clothing shop in Newtown named after a beloved trans elder, raising funds for Gender Minorities Aotearoa. A safe, affirming place to browse, volunteer and chat, whatever your gender or style.', '130 Riddiford Street, Newtown', 'Wellington', -41.3121, 174.7794, '04 385 0611', null, 'https://auntydanas.com/', array['op shop','clothing','volunteering','trans','fundraising']::text[], 'lgbt_managed', true),
('Rainbow Wellington', 'resource', 'Community', 'A membership association running since 1997 with a busy social calendar of pub nights, quizzes, walks, dinners, board games and picnics across the region. One of the easiest ways for rainbow people of any age to build a local friend group.', 'Events held at venues across Wellington', 'Wellington', -41.2785, 174.7795, null, 'hello@rainbowwellington.org.nz', 'https://rainbowwellington.org.nz/', array['social','networking','events','advocacy']::text[], 'lgbt_managed', true),
('Tīwhanawhana Trust', 'resource', 'Community', 'Wellington''s takatāpui community group, welcoming people of all sexualities and genders to tell their stories, sing waiata and practise kapa haka together. Regular Monday evening gatherings are a warm doorway into Māori rainbow community.', 'Meets at Level 4, 204 Willis Street, Te Aro', 'Wellington', -41.2932, 174.7723, null, null, 'http://www.tiwhanawhana.com/', array['takatāpui','kapa haka','waiata','culture','support']::text[], 'lgbt_managed', true),
('Wellington Pride Festival | Tū whakahīhī e Te Whanganui-ā-Tara', 'resource', 'Community', 'The longest-running annual Pride celebration in Aotearoa, held every March with weeks of community events including the Out in the City fair and the Pride Parade. Entirely volunteer-led, so joining the crew is a fantastic way to make friends while giving back.', 'Festival events at venues across Wellington each March', 'Wellington', -41.289, 174.7772, null, null, 'https://www.wellingtonpridefestival.com/', array['pride','festival','events','volunteering']::text[], 'lgbt_managed', true),
('The Glamaphones', 'resource', 'Community', 'Wellington''s rainbow community choir of around 60 voices, singing together since 2011 with a strong emphasis on participation and inclusion over audition-perfect polish. Weekly Thursday rehearsals at St Andrew''s on The Terrace are open to newcomers.', 'Rehearses at St Andrew''s on The Terrace, 30 The Terrace', 'Wellington', -41.2814, 174.7749, null, null, 'https://www.glamaphones.org.nz/', array['choir','singing','music','inclusion']::text[], 'lgbt_managed', true),
('Burnett Foundation Aotearoa – Āwhina Centre', 'resource', 'Healthcare', 'The Wellington centre of Aotearoa''s leading HIV and sexual health organisation, offering free testing, information and peer support in a friendly, judgement-free space. Staff and volunteers from the community make it a comfortable place to look after your health.', '220 Willis Street, Te Aro', 'Wellington', -41.2937, 174.7717, null, null, 'https://www.burnettfoundation.org.nz/', array['sexual health','hiv','testing','support']::text[], 'lgbt_managed', true),
('Evolve Wellington Youth Service', 'resource', 'Healthcare', 'A free youth one-stop-shop in the James Smith Building offering doctors, nurses, counselling and social support for anyone aged 10-25, with a dedicated rainbow group among its programmes. A safe, affirming place for young people to get care and connect.', 'Level 2, James Smith Building, 65 Cuba Street (cnr Manners Street), Te Aro', 'Wellington', -41.2896, 174.7762, '04 473 6204', 'reception@evolveyouth.org.nz', 'https://www.evolveyouth.org.nz/', array['youth','health','counselling','rainbow group','free']::text[], 'ally', true),
('Different Strokes Wellington', 'resource', 'Community', 'Wellington''s LGBTQIA+ swimming club, running coached sessions on Monday and Thursday evenings with social drinks afterwards twice a month. All abilities and identities are welcome — many members join as much for the friendships as the fitness.', 'Swims at Wellington Regional Aquatic Centre, 63 Kilbirnie Crescent, Kilbirnie', 'Wellington', -41.3186, 174.7946, null, null, 'https://dsw.org.nz/', array['swimming','sports','fitness','social']::text[], 'lgbt_managed', true),
('OuterSpaces (School''s Out & Tranzform)', 'resource', 'Community', 'The umbrella trust behind Wellington''s rainbow youth groups: School''s Out for LGBTQIA+ 12-18 year olds, Tranzform for gender diverse young people aged 15-30, plus the Wellington Binder Exchange. Weekly peer groups offer a safe, fun way to find your community.', 'Groups meet weekly in central Wellington and Lower Hutt', 'Wellington', -41.29, 174.777, null, null, 'https://www.outerspaces.org.nz/', array['youth','support','trans','social groups']::text[], 'lgbt_managed', true),
('Naming New Zealand', 'resource', 'Services', 'A Wellington-based charity helping trans, gender diverse, takatāpui and intersex young people update their identity documents, with grants that cover costs like birth certificates and passports. Practical, affirming support with four grant rounds a year.', 'Greater Wellington region (part of the OuterSpaces/RainbowYOUTH whānau)', 'Wellington', -41.29, 174.777, null, null, 'http://www.naming.nz/', array['trans','id documents','grants','youth']::text[], 'lgbt_managed', true),
('Cruz Bar & Nightclub', 'business', 'Nightlife', 'Christchurch''s longest-running gay bar and nightclub, a welcoming home base for the local rainbow community for over three decades. A friendly spot to meet people on the dance floor or over a quiet drink, with DJs, drag shows and themed nights from Wednesday to Sunday.', '77 Victoria Street, Christchurch Central', 'Christchurch', -43.5237, 172.632, '+64 3 379 2910', null, 'http://cruz.co.nz', array['nightclub','dancing','drag','music','social']::text[], null, true),
('Flux Ōtautahi', 'business', 'Nightlife', 'An alternative bar and performance space in the Boxed Quarter known for its queer dance parties, live gigs and genuinely inclusive crowd. A great low-pressure place to find your people through music, from house nights to queer-focused events like Queer Horizons.', '270 St Asaph Street, Boxed Quarter, Christchurch Central', 'Christchurch', -43.5376, 172.641, null, null, 'https://www.facebook.com/fluxx.capacitor/', array['live music','performance','dancing','arts','inclusive']::text[], 'ally', true),
('Rollickin Gelato', 'business', 'Cafes', 'A much-loved dessert cafe on historic New Regent Street that is a registered Safe Space Alliance venue and a regular Christchurch Pride supporter, hosting events like the annual Pride Dog Walk. Open late, it''s an easy, alcohol-free spot to catch up with new friends over a scoop.', '35 New Regent Street, Christchurch Central', 'Christchurch', -43.5291, 172.638, null, null, 'https://www.rollickin.co.nz', array['gelato','dessert','cafe','safe space','late night']::text[], 'ally', true),
('Qtopia', 'resource', 'Community', 'Ōtautahi''s hub for rainbow advocacy and social support, running weekly youth social groups, trans and non-binary peer support with lived-experience workers, and community events across Waitaha Canterbury. A warm first port of call for anyone wanting connection with the local rainbow community.', '213 Lichfield Street, Christchurch Central', 'Christchurch', -43.5347, 172.6386, '+64 20 4080 1084', 'connect@qtopia.org.nz', 'https://qtopia.org.nz', array['support','youth','peer support','social groups','trans']::text[], 'lgbt_managed', true),
('Ōtautahi Christchurch Pride', 'resource', 'Community', 'The volunteer-run charitable trust behind the annual March pride festival, plus year-round community events like the Rainbow Ride, pride picnic and interfaith service. Volunteering or attending their events is one of the easiest ways to meet rainbow whānau across the city.', 'Central Christchurch (city-wide festival and events)', 'Christchurch', -43.5309, 172.6365, null, 'contact@chchpride.co.nz', 'https://www.chchpride.co.nz', array['pride','festival','events','volunteering','community']::text[], 'lgbt_managed', true),
('Burnett Foundation Aotearoa – Te Toka Centre', 'resource', 'Healthcare', 'The Christchurch centre of Aotearoa''s HIV prevention and support organisation, offering free rapid HIV and STI testing, counselling, and non-judgemental advice in a rainbow-affirming space. Staff are friendly and the vibe is welcoming, not clinical.', 'Unit 1, 275 Cashel Street, Christchurch Central', 'Christchurch', -43.5333, 172.644, '+64 3 379 1953', null, 'https://www.burnettfoundation.org.nz', array['sexual health','hiv testing','counselling','support','free']::text[], null, true),
('Te Tahi Youth (formerly 298 Youth Health)', 'resource', 'Healthcare', 'A free one-stop health and wellbeing service for young people aged 10-24, covering GP care, sexual health, counselling and youth development in a rainbow-friendly environment. A safe, supportive place for queer young people to look after themselves.', 'Unit 1, Amuri Park, 25 Churchill Street, St Albans', 'Christchurch', -43.5192, 172.6435, '+64 3 943 9298', null, 'https://tetahiyouth.org.nz', array['youth','health','mental health','free','counselling']::text[], 'ally', true),
('Sexual Wellbeing Aotearoa Christchurch', 'resource', 'Healthcare', 'The Christchurch clinic of the national sexual and reproductive health service (formerly Family Planning), offering affirming, judgement-free care for all genders and orientations.', '9 Washington Way, Sydenham', 'Christchurch', -43.541, 172.6347, null, null, 'https://sexualwellbeing.org.nz/canterbury/christchurch', array['sexual health','clinic','contraception','inclusive','low cost']::text[], 'ally', true),
('The Women''s Centre Christchurch', 'resource', 'Community', 'A safe, supportive drop-in space for women, including trans women and non-binary people who feel at home in women''s spaces, with free counselling (lesbian-identifying counsellors available on request), a lesbian library collection and a monthly lesbian movie night. A gentle way to build community connections.', '48 Fitzgerald Avenue, Christchurch Central', 'Christchurch', -43.5348, 172.6494, '+64 3 371 7414', 'admin@womenscentre.co.nz', 'https://womenscentre.co.nz', array['women','lesbian','non-binary','counselling','drop-in']::text[], 'ally', true),
('Kindred', 'resource', 'Community', 'A Christchurch organisation providing support and social connection for young trans people and their whānau. Get in touch by email to find out about gatherings where trans young people and their families can meet others walking the same path.', 'Christchurch (meets at community venues)', 'Christchurch', -43.532, 172.6362, null, 'support@kindred.org.nz', null, array['trans','youth','whanau','support','social connection']::text[], null, true),
('Lambda Trampers & Lambda Latte Walkers', 'resource', 'Community', 'A friendly social tramping and walking group for the LGBTQ+ community and friends, running since the early 1980s. Choose full-day tramps around Canterbury or shorter 2-3 hour Latte Walks that finish with coffee and a chat — a relaxed way to make friends outdoors.', 'Day walks and tramps around Canterbury', 'Christchurch', -43.53, 172.63, null, null, 'https://lambdatrampers.org', array['tramping','walking','outdoors','social','coffee']::text[], 'lgbt_managed', true),
('Christchurch Heroes Inclusive Sports Trust', 'resource', 'Community', 'The South Island''s first LGBTI+ inclusive rugby team, now a charitable trust running social touch rugby, badminton and other sport and social events. No experience needed — it''s about teammates, fitness and friendship in a judgement-free environment.', 'Sessions at sports venues across Christchurch', 'Christchurch', -43.538, 172.623, null, null, 'https://www.chchheroes.nz', array['sports','rugby','badminton','inclusive','social']::text[], 'lgbt_managed', true),
('UC Rainbow Equity', 'resource', 'Services', 'The University of Canterbury''s dedicated rainbow support service, connecting LGBTQIA+ students with advice, advocacy and community on campus. A great starting point for queer students new to Ōtautahi looking to find their crowd.', 'University of Canterbury, 20 Kirkwood Avenue, Upper Riccarton', 'Christchurch', -43.5228, 172.5836, null, null, 'https://www.canterbury.ac.nz/life/support-and-wellbeing/uc-support-services/rainbow-equity', array['students','university','support','advocacy','youth']::text[], 'ally', true);